create extension if not exists pgcrypto;
create table if not exists profiles (id uuid primary key, email text, name text, role text not null default 'driver' check (role in ('driver','moderator','admin')), created_at timestamptz not null default now());
create table if not exists vehicles (id text primary key, brand text not null, model text not null, usable_kwh numeric not null, max_ac_kw numeric not null, max_dc_kw numeric not null, ac_connector text not null, dc_connector text not null, consumption_kwh_100 numeric not null);
create table if not exists stations (id text primary key, name text not null, operator text, address text not null, city text not null, lat double precision not null, lng double precision not null, tariff_kwh numeric, payment text, status text not null, freshness text, confidence numeric, last_verified date, source_name text, source_url text, created_at timestamptz not null default now());
create table if not exists connectors (id uuid primary key default gen_random_uuid(), station_id text not null references stations(id) on delete cascade, type text not null, current_type text not null, power_kw numeric not null, quantity integer not null default 1, status text not null default 'operational');
create table if not exists validations (id uuid primary key default gen_random_uuid(), station_id text not null references stations(id) on delete cascade, user_id uuid references profiles(id), outcome text not null check (outcome in ('working','degraded','offline','inaccessible')), observed_power_kw numeric, observed_price_kwh numeric, required_app text, notes text, occurred_at timestamptz not null default now());
create table if not exists charge_sessions (id uuid primary key default gen_random_uuid(), station_id text not null references stations(id), user_id uuid references profiles(id), vehicle_id text references vehicles(id), started_at timestamptz not null, ended_at timestamptz, energy_kwh numeric, cost numeric, start_soc integer, end_soc integer, status text not null check (status in ('completed','failed','abandoned')), notes text, created_at timestamptz not null default now());
create index if not exists stations_geo_idx on stations(lat,lng);
create index if not exists validations_station_time_idx on validations(station_id,occurred_at desc);
create index if not exists sessions_user_time_idx on charge_sessions(user_id,started_at desc);
